/// <summary>
/// this class will be used for sales order posting for landed cost module outbound orders
/// </summary>
internal final class ETGOTMSalesFormLetterProvider extends SalesFormletterProvider
{
    private CustInvoiceJour custInvoiceJour;

}

Method.Source:
[Hookable(false)]
internal static ETGOTMSalesFormLetterProvider construct()
{
    return new ETGOTMSalesFormLetterProvider();
}

[Hookable(false)]
internal CustInvoiceJour parmITMJournalTable(CustInvoiceJour _journalTable = custInvoiceJour)
{
    custInvoiceJour = _journalTable;
    return custInvoiceJour;
}

protected boolean checkHeading()
{
    boolean ret;

    ret = super();

    ETGOTMFormLetterContext itmFormLetterContext = ETGOTMFormLetterContext::instance();
    if ((!itmFormLetterContext || !itmFormLetterContext.parmSkipITMGoodsInTransitControlCheck())
        && DlvTerm::find(salesTable.DlvTerm).ITMGoodsInTransitControl
        && this.parmDocumentStatus() == DocumentStatus::PackingSlip)
    {
        ret = checkFailed("@InboundTransportationManagement:ReceiptPostingIsNotAllowedForOrdersUsingGoodsIn");
    }

    return ret;
}
